const gift_img_URLs = [
    "https://hattendo.jp/shop/g/gC129/",
    "https://cake.jp/item/3415022/",
    "https://www.beniharuka.jp/view/item/000000000018",
    "http://oitea-lab.shop/?pid=157485820"
],
    gift_button_URLs = [
        "https://gift.epark.jp/hattendo/",
        "https://gift.epark.jp/cake-jp/",
        "https://gift.epark.jp/beniharuka/",
        "https://gift.epark.jp/oitea-lab/"
    ];

// URLを新しいウィンドウで開く関数
function openURLInNewWindow(url) {
    // URLが有効かチェック
    if (isValidURL(url)) {
        window.open(url, "_blank");
    } else {
        console.error('Invalid URL: ' + url);
    }
}

// 画像のURLを開く関数
function giftImgURL(index) {
    if (index >= 0 && index < gift_img_URLs.length) {
        openURLInNewWindow(gift_img_URLs[index]);
    } else {
        console.error('Invalid index for gift_img_URLs: ' + index);
    }
}

// ボタンのURLを開く関数
function giftButtonURL(index) {
    if (index >= 0 && index < gift_button_URLs.length) {
        openURLInNewWindow(gift_button_URLs[index]);
    } else {
        console.error('Invalid index for gift_button_URLs: ' + index);
    }
}

// URLのバリデーション関数
function isValidURL(url) {
    try {
        new URL(url);
        return true;
    } catch (e) {
        return false;
    }
}
